import{_ as a,o,c as r,ag as t}from"./chunks/framework.CAXxHpAX.js";const g=JSON.parse('{"title":"Changelog","description":"What changed, when.","frontmatter":{"description":"What changed, when."},"headers":[],"relativePath":"reference/changelog.md","filePath":"reference/changelog.md","lastUpdated":1777130260000}'),l={name:"reference/changelog.md"};function i(n,e,d,s,c,p){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>Reverse chronological. Tags follow <a href="https://semver.org/" target="_blank" rel="noreferrer">SemVer</a> for the SDK, CLI, and HTTP API independently.</p><h2 id="v0-4-2-—-2026-04-25" tabindex="-1">v0.4.2 — 2026-04-25 <a class="header-anchor" href="#v0-4-2-—-2026-04-25" aria-label="Permalink to &quot;v0.4.2 — 2026-04-25&quot;">​</a></h2><p><strong>The clients-first release.</strong> This is the one where Prova actually became usable.</p><ul><li>New: web upload page at <a href="https://prova.network/upload/" target="_blank" rel="noreferrer">prova.network/upload/</a> — drag-and-drop, no install, no wallet, 100 MB free per file</li><li>New: CLI <code>@prova-network/cli</code> (<code>prova auth | put | get | ls | whoami | logout</code>)</li><li>New: dashboard at <a href="https://prova.network/app/" target="_blank" rel="noreferrer">prova.network/app/</a> — token mint, file list, usage chart, revoke</li><li>New: HTTP API tokens (HS256 JWT, scoped, revocable, 1-year expiry)</li><li>New: 6 documented endpoints — <code>/api/auth/signup</code>, <code>/api/upload</code>, <code>/p/{cid}</code>, <code>/api/files</code>, <code>/api/usage</code>, <code>/api/tokens/{list,revoke}</code></li><li>Wired: domain <code>prova.network</code> (apex + www CNAME-flattened to Pages, <code>p.prova.network</code> for the staging server with Origin CA cert)</li><li>Wired: docs at <code>docs.prova.network</code> (you are here)</li><li>Internal: 16-finding security audit shipped — see <code>SECURITY-AUDIT-2026-04-25.md</code> in the repo</li><li>Outstanding: real CommP in browser, magic-link email verify, Origin/CSRF guard, abuse + CSAM hook (all tracked for pre-public-testnet)</li></ul><h2 id="v0-4-1-—-2026-04-24" tabindex="-1">v0.4.1 — 2026-04-24 <a class="header-anchor" href="#v0-4-1-—-2026-04-24" aria-label="Permalink to &quot;v0.4.1 — 2026-04-24&quot;">​</a></h2><p>Visual / brand pass.</p><ul><li>New: live WebGL Earth hero on prova.network</li><li>New: animated architecture and lifecycle diagrams (real motion, not GIFs)</li><li>New: notarial-seal logo</li><li>Apple system font stack</li><li>Both dark and light themes</li></ul><h2 id="v0-4-0-—-2026-04-22" tabindex="-1">v0.4.0 — 2026-04-22 <a class="header-anchor" href="#v0-4-0-—-2026-04-22" aria-label="Permalink to &quot;v0.4.0 — 2026-04-22&quot;">​</a></h2><p>The Ethereum-native pivot.</p><ul><li>Renamed and reframed: Prova is now verifiable storage on Base, not an L1 chain</li><li><code>Synapse</code> → <code>Prova</code> rename across the SDK</li><li>Dropped: PoRep, sealing, FVM dependencies</li><li>Forked: FilOzone PDP contracts, adapted to Base + USDC</li><li>Forked: synapse-sdk → @prova-network/sdk</li></ul><h2 id="v0-3-and-earlier" tabindex="-1">v0.3 and earlier <a class="header-anchor" href="#v0-3-and-earlier" aria-label="Permalink to &quot;v0.3 and earlier&quot;">​</a></h2><p>The L1 era. Archived under <code>archive/v1-l1-chain</code> in the repo.</p><h2 id="roadmap-next" tabindex="-1">Roadmap (next) <a class="header-anchor" href="#roadmap-next" aria-label="Permalink to &quot;Roadmap (next)&quot;">​</a></h2><ul><li><strong>v0.5</strong> — magic-link email verify, Origin/CSRF guards, abuse hook, CSP/HSTS, real CommP in browser. Also: testnet contracts deployed to Base Sepolia.</li><li><strong>v0.6</strong> — real on-chain dealmaking from the upload page. Sponsor wallet, sponsor prover. CLI <code>prova put</code> returns a real deal-id.</li><li><strong>v0.7</strong> — wallet-paid uploads. Custom terms. Custom redundancy.</li><li><strong>v0.8</strong> — public testnet open to all.</li><li><strong>v1.0</strong> — mainnet. Audit complete. SLAs published.</li></ul>',15)])])}const u=a(l,[["render",i]]);export{g as __pageData,u as default};
